const API_URL = process.env.REACT_APP_API_URL || "http://localhost:5000/api";

const getAuthHeaders = () => {
    const savedUser = localStorage.getItem('user-session');
    if (savedUser) {
        const { token } = JSON.parse(savedUser);
        return {
            'Content-Type': 'application/json',
            'Authorization': `Bearer ${token}`
        };
    }
    return { 'Content-Type': 'application/json' };
};

export const api = {
    // --- AUTH ---
    login: async (email, password) => {
        // Limpiamos el email antes de enviarlo
        const emailLimpio = email.trim().toLowerCase();

        const response = await fetch(`${API_URL}/auth/login`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ correo: emailLimpio, password })
        });

        const data = await response.json();
        if (!response.ok) {
            throw new Error(data.msg || "Error en el login");
        }
        return data; // Retorna { token, user: { id, nombre, rol, ... } }
    },

    registro: async (datos) => {
        // Aseguramos que el correo vaya limpio en el registro también
        if(datos.correo) datos.correo = datos.correo.trim().toLowerCase();

        const response = await fetch(`${API_URL}/auth/registro`, {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(datos)
        });
        const data = await response.json();
        if (!response.ok) {
            throw new Error(data.msg || "Error al registrar usuario");
        }
        return data;
    },

    // ... (resto de funciones: getLocalesVendedor, crearLocal, etc. se mantienen igual)
    getLocalesVendedor: async (vendedorId) => {
        const res = await fetch(`${API_URL}/locales/vendedor/${vendedorId}`, {
            headers: getAuthHeaders()
        });
        return await res.json();
    },

    crearLocal: async (data) => {
        const res = await fetch(`${API_URL}/locales`, {
            method: 'POST',
            headers: getAuthHeaders(),
            body: JSON.stringify(data) 
        });
        return await res.json();
    }
};
